import { useState, useEffect } from 'react'
import '../styles/navbar.css'

/* ─── Navbar ───────────────────────────────────────────────────────────────
   Features
   • Fixed top, glass-blur background on scroll
   • Dot indicator under active nav link
   • "Hire Me" CTA button
   • Animated hamburger → slide-in drawer on mobile
   ─────────────────────────────────────────────────────────────────────── */

const NAV_LINKS = [
  { label: 'Home',     href: '#home'     },
  { label: 'About',    href: '#about'    },
  { label: 'Skills',   href: '#skills'   },
  { label: 'Projects', href: '#projects' },
  { label: 'Contact',  href: '#contact'  },
]

const Navbar = () => {
  const [menuOpen,      setMenuOpen]      = useState(false)
  const [scrolled,      setScrolled]      = useState(false)
  const [activeSection, setActiveSection] = useState('home')

  /* Scroll handler — detect scroll depth & active section */
  useEffect(() => {
    const onScroll = () => {
      setScrolled(window.scrollY > 60)

      const sectionIds = NAV_LINKS.map(l => l.href.replace('#', ''))
      const scrollPos  = window.scrollY + 120

      for (const id of sectionIds) {
        const el = document.getElementById(id)
        if (el && scrollPos >= el.offsetTop && scrollPos < el.offsetTop + el.offsetHeight) {
          setActiveSection(id)
          break
        }
      }
    }

    window.addEventListener('scroll', onScroll, { passive: true })
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  /* Prevent body scroll when drawer is open */
  useEffect(() => {
    document.body.style.overflow = menuOpen ? 'hidden' : ''
    return () => { document.body.style.overflow = '' }
  }, [menuOpen])

  const closeMenu = () => setMenuOpen(false)

  return (
    <>
      <nav className={`navbar ${scrolled ? 'scrolled' : ''}`}>
        <div className="nav-container">

          {/* Logo */}
          <a href="#home" className="nav-logo" onClick={closeMenu}>
            <span className="logo-bracket">&lt;</span>
            Harshini
            <span className="logo-bracket">/&gt;</span>
          </a>

          {/* Desktop links */}
          <ul className="nav-links">
            {NAV_LINKS.map(link => (
              <li key={link.label}>
                <a
                  href={link.href}
                  className={activeSection === link.href.replace('#', '') ? 'active' : ''}
                >
                  {link.label}
                </a>
              </li>
            ))}
            <li>
              <a href="#contact" className="btn btn-primary nav-cta">
                Hire Me
              </a>
            </li>
          </ul>

          {/* Hamburger button */}
          <button
            className={`hamburger ${menuOpen ? 'open' : ''}`}
            onClick={() => setMenuOpen(prev => !prev)}
            aria-label="Toggle navigation"
            aria-expanded={menuOpen}
          >
            <span />
            <span />
            <span />
          </button>
        </div>
      </nav>

      {/* Mobile drawer overlay */}
      <div
        className={`nav-overlay ${menuOpen ? 'visible' : ''}`}
        onClick={closeMenu}
        aria-hidden="true"
      />

      {/* Mobile drawer */}
      <div className={`nav-drawer ${menuOpen ? 'open' : ''}`}>
        <ul className="drawer-links">
          {NAV_LINKS.map(link => (
            <li key={link.label}>
              <a
                href={link.href}
                className={activeSection === link.href.replace('#', '') ? 'active' : ''}
                onClick={closeMenu}
              >
                {link.label}
              </a>
            </li>
          ))}
          <li>
            <a href="#contact" className="btn btn-primary drawer-cta" onClick={closeMenu}>
              Hire Me
            </a>
          </li>
        </ul>
      </div>
    </>
  )
}

export default Navbar
